        // If there is at least one matching character, we can form a palindrome of length count * 2 + 1
        // Otherwise, it's just 1
        maxLen = Math.max(maxLen, count * 2 + 1);

        memo.set(key, maxLen);
        return maxLen;
    }

    let maxLength = 1;
    for (let i = 0; i < n; i++) {
        const visited = 1 << i;
        const currentLen = dfs(i, visited);
        maxLength = Math.max(maxLength, currentLen);
    }

    return maxLength;
}

